'use client'
import { cn, useSignal, useSignalEffect, useSignals } from '@cascivo/core'
import { builtin, t } from '@cascivo/i18n'
import { useRef, type ReactNode } from 'react'
import styles from './header-panel.module.css'

export interface HeaderPanelLabels {
  close?: string
}

export interface HeaderPanelProps {
  open: boolean
  onClose: () => void
  label: string
  children: ReactNode
  labels?: HeaderPanelLabels
  className?: string | undefined
}

export function HeaderPanel({
  open,
  onClose,
  label,
  children,
  labels,
  className,
}: HeaderPanelProps) {
  useSignals()
  const panelRef = useRef<HTMLDivElement>(null)
  const restoreRef = useRef<HTMLElement | null>(null)
  const isOpen = useSignal(open)
  isOpen.value = open
  const onCloseRef = useRef(onClose)
  onCloseRef.current = onClose

  useSignalEffect(() => {
    const el = panelRef.current
    if (!el) return
    if (isOpen.value) {
      restoreRef.current = document.activeElement as HTMLElement | null
      try {
        el.showPopover()
      } catch {
        /* jsdom or already shown */
      }
      el.focus()
    } else {
      try {
        el.hidePopover()
      } catch {
        /* jsdom or already hidden */
      }
      restoreRef.current?.focus()
      restoreRef.current = null
    }
  })

  useSignalEffect(() => {
    const el = panelRef.current
    if (!el) return
    const handler = (e: Event) => {
      const isClosing = 'newState' in e ? (e as ToggleEvent).newState === 'closed' : true
      if (isOpen.peek() && isClosing) onCloseRef.current()
    }
    el.addEventListener('toggle', handler)
    return () => el.removeEventListener('toggle', handler)
  })

  return (
    <div
      ref={panelRef}
      popover="auto"
      role="region"
      aria-label={label}
      tabIndex={-1}
      data-state={open ? 'open' : 'closed'}
      className={cn(styles['panel'], className)}
    >
      <div className={styles['header']}>
        <span className={styles['title']}>{label}</span>
        <button
          type="button"
          aria-label={labels?.close ?? t(builtin.headerPanel.close)}
          className={styles['close']}
          onClick={() => onCloseRef.current()}
        >
          <svg viewBox="0 0 16 16" width="14" height="14" aria-hidden="true">
            <path
              d="M4 4l8 8M12 4l-8 8"
              stroke="currentColor"
              strokeWidth="1.5"
              strokeLinecap="round"
            />
          </svg>
        </button>
      </div>
      <div className={styles['body']}>{children}</div>
    </div>
  )
}

@layer cascivo.component {
  .panel {
    position: fixed;
    inset-block-start: var(--cascivo-shell-header-block-size, 3rem);
    inset-inline-end: 0;
    inset-inline-start: auto;
    inset-block-end: 0;
    margin: 0;
    inline-size: var(--cascivo-shell-panel-inline-size, 20rem);
    max-inline-size: 100vw;
    display: none;
    flex-direction: column;
    padding: 0;
    background: var(--cascivo-color-surface);
    border: none;
    border-inline-start: 1px solid var(--cascivo-color-border);
    box-shadow: var(--cascivo-shadow-md);
    overscroll-behavior: contain;

    &:popover-open {
      display: flex;
    }

    translate: 100% 0;
    transition:
      translate var(--cascivo-motion-enter),
      display var(--cascivo-motion-enter) allow-discrete,
      overlay var(--cascivo-motion-enter) allow-discrete;

    @starting-style {
      &:popover-open {
        translate: 100% 0;
      }
    }

    &:popover-open {
      translate: 0 0;
    }
  }

  .header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    flex-shrink: 0;
    padding: var(--cascivo-space-3);
    border-block-end: 1px solid var(--cascivo-color-border);
  }

  .title {
    font-family: var(--cascivo-font-sans);
    font-size: var(--cascivo-text-sm);
    font-weight: var(--cascivo-font-semibold);
    color: var(--cascivo-color-text);
  }

  .close {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    padding: var(--cascivo-space-1);
    color: var(--cascivo-color-text-subtle);
    background: transparent;
    border: none;
    border-radius: var(--cascivo-radius-control);
    cursor: pointer;
    transition: color var(--cascivo-duration-150) var(--cascivo-ease-out);

    &:hover {
      color: var(--cascivo-color-text);
      background-color: var(--cascivo-color-bg-subtle);
    }

    &:focus-visible {
      outline: none;
      box-shadow: var(--cascivo-focus-ring);
    }
  }

  .body {
    flex: 1;
    overflow-y: auto;
    padding: var(--cascivo-space-3);
  }
}
